-- migrations/018_sales_templates.sql
-- 20 продажных шаблонов WhatsApp: 5П (Приветствие → Присоединение → Прояснение
-- → Презентация → Призыв) + SPIN (Ситуация → Проблема → Извлечение → Направление).
-- Цель — довести клиента до подписания договора услуг.
--
-- !!! ВНИМАНИЕ !!! ЭТА МИГРАЦИЯ НЕ ПРИМЕНЕНА АВТОМАТИЧЕСКИ.
-- !!! Выполнить в Supabase → SQL Editor. Идемпотентна: on conflict do nothing,
-- !!! повторный запуск ничего не сломает и не затрёт правки владельца.
--
-- ВАЖНО про E'' : в обычных кавычках Postgres понимает \n БУКВАЛЬНО (два символа).
-- Так и произошло в миграции 005 — шаблоны /документы, /расчёт, /этапы ушли в базу
-- с торчащими \n вместо переносов строк. Только E'...' даёт настоящий перенос.

on conflict (trigger) do nothing;

-- Проверка
select trigger, title, sort_order from wa_quick_replies order by sort_order;
