insert into wa_quick_replies (trigger, title, body, category, sort_order) values
  (E'/контакт', E'1. Первое касание (5П)', E'Здравствуйте, {{имя}}! 👋\nМеня зовут {{менеджер}}, я ваш ипотечный специалист.\n\nПомогу подобрать программу и посчитать, на что вы реально проходите — ДО того, как подавать заявку в банк.\n\nЧтобы не гадать: квартиру для себя смотрите или под сдачу? И в каком городе?', E'greeting', 11),
  (E'/ситуация', E'2. SPIN: ситуационные вопросы', E'{{имя}}, чтобы посчитать точно, подскажите 4 момента 👇\n\n1️⃣ Какая примерно стоимость квартиры?\n2️⃣ Сколько готовы внести первоначальным?\n3️⃣ Официальный доход есть? ОПВ отчисляются?\n4️⃣ Действующие кредиты или рассрочки есть?\n\nОтветите — сегодня же пришлю расчёт по подходящим программам.', E'general', 12),
  (E'/проблема', E'3. SPIN: проблемные вопросы', E'{{имя}}, а что пока мешает выйти на сделку?\n\nЧаще всего одно из трёх:\n• банк режет сумму из-за нагрузки по действующим кредитам\n• не хватает первоначального взноса\n• доход не подтверждается официально\n\nУ вас что ближе? Разберём — почти под каждый случай есть решение.', E'general', 13),
  (E'/последствия', E'4. SPIN: извлекающие (цена бездействия)', E'{{имя}}, смотрите, как это обычно выходит 👇\n\nОтказ банка не исчезает — он остаётся в вашей кредитной истории. Три-четыре отказа подряд, и следующий банк смотрит на вас уже хуже, чем в самом начале.\n\nПлюс на переподачу уходит 2-3 недели. Квартира, которая понравилась, за это время уходит другому.\n\nГотовы рискнуть историей, подавая наугад? Или сначала посмотрим, где вы точно проходите?', E'general', 14),
  (E'/выгода', E'5. SPIN: направляющие (клиент сам видит пользу)', E'{{имя}}, правильно понимаю: если бы вы заранее знали, какой банк вас одобрит и на какую сумму — вы бы не тратили месяцы на отказы и вышли на сделку быстрее?\n\nРовно это мы и делаем: сначала считаем и проверяем историю, потом подаём — точечно, туда, где вы проходите.\n\nНасколько это для вас сейчас актуально?', E'general', 15),
  (E'/боль', E'6. Был отказ банка — работа с болью', E'{{имя}}, отказ — это не приговор, это диагноз 🩺\n\nУ банка всегда есть конкретная причина: нагрузка, просрочки в прошлом, стаж, неподтверждённый доход. Вам её не назовут.\n\nПока причина не найдена — следующая заявка уйдёт туда же.\n\nДавайте поднимем вашу кредитную историю и найдём настоящую причину. Тогда будем подавать не вслепую.', E'rejection', 16),
  (E'/самбанк', E'7. Возражение «сам схожу в банк»', E'{{имя}}, конечно, сходить можно — иногда этого хватает 👌\n\nОдин нюанс: в банке вам покажут программы этого банка. Кредитный менеджер не станет сравнивать вас с условиями соседей — это не его работа.\n\nМы смотрим по всем банкам сразу и подаём туда, где выше шанс и ниже платёж.\n\nЕсли вы уже были в банке — скажите, что ответили? Разберу бесплатно, что там пошло не так.', E'general', 17),
  (E'/дорого', E'8. Возражение «дорого»', E'{{имя}}, понимаю 👍 Давайте на цифрах.\n\nНаша услуга — разовая. Ошибка в ипотеке — на 15-25 лет.\n\nРазница в 1% ставки на кредите 20 млн ₸ — это сотни тысяч тенге переплаты в год. Не тот банк или не та программа — и вы платите эту разницу весь срок.\n\nМы окупаемся уже на подборе программы. Показать на вашем расчёте, где именно?', E'general', 18),
  (E'/зачемвы', E'9. Возражение «в банке бесплатно»', E'{{имя}}, справедливый вопрос 🙂\n\nВ банке с вами работают как с одной заявкой в этот банк. Мы работаем с вашей задачей: разобрать историю, убрать стоп-факторы, выбрать программу и банк, довести до выдачи.\n\nБанку в целом всё равно, одобрят вас или нет. Нам — нет: мы получаем результат только когда вы получаете деньги.\n\nЧто для вас важнее: скорость или минимальный платёж?', E'general', 19),
  (E'/подумаю', E'10. Возражение «я подумаю»', E'{{имя}}, конечно, подумайте 👌\n\nТолько подскажите честно, чтобы я не гадал: не хватает информации, не подошла цена услуги или сейчас просто не время?\n\nЕсли не хватает цифр — пришлю расчёт, будете думать предметно, а не в воздух.', E'general', 20),
  (E'/гарантия', E'11. Возражение «гарантируете одобрение?»', E'{{имя}}, скажу честно: гарантировать одобрение не может никто — решение всегда за банком. Кто обещает 100% — тот обманывает 🚫\n\nЧто гарантируем мы:\n• разберём вашу историю и назовём реальные шансы ДО подачи\n• подадим туда, где они выше\n• не дадим наловить отказов вслепую\n\nЕсли по цифрам вы не проходите — скажу прямо и не возьму в работу. Так честнее для нас обоих.', E'general', 21),
  (E'/супруга', E'12. Возражение «посоветуюсь с семьёй»', E'Конечно, {{имя}}, такие решения принимают вместе 👨‍👩‍👧\n\nДавайте пришлю расчёт сюда — покажете второй половине, обсудите спокойно.\n\nМогу и созвониться с вами двоими и ответить на вопросы сразу — так обычно быстрее. Когда удобно?', E'general', 22),
  (E'/кейс', E'13. Социальное доказательство (случай)', E'{{имя}}, свежий случай — почти ваша ситуация 👇\n\nКлиенту отказали в двух банках подряд. Подняли историю: висела старая рассрочка на 15 000 ₸ — она и резала нагрузку. Закрыли, дождались обновления, подали в третий банк — одобрили.\n\nСам он про эту рассрочку даже не помнил.\n\nХотите, посмотрим, что тянет вниз именно вас?', E'general', 23),
  (E'/ценность', E'14. Что входит в договор (презентация)', E'{{имя}}, вот что вы получаете по договору 👇\n\n✅ Разбор кредитной истории и ОПВ — находим стоп-факторы\n✅ Расчёт по всем подходящим программам, а не по одной\n✅ Подбор банка под вашу ситуацию\n✅ Подготовка документов и подача\n✅ Сопровождение до выдачи денег: оценка, нотариус, регистрация\n✅ Ваш специалист на связи на каждом шаге\n\nРаботаем на результат: вы получаете деньги — мы своё.', E'general', 24),
  (E'/договор', E'15. Призыв подписать договор', E'{{имя}}, по цифрам вы проходите ✅ Предлагаю закрепить и начать.\n\nПодписываем договор — и я сразу сажусь за вашу заявку: история, документы, подача.\n\nДоговор подписываем онлайн, ехать никуда не нужно. Сумма — {{сумма}} ₸.\n\nСкинуть договор на ознакомление?', E'general', 25),
  (E'/дожим', E'16. Мягкий дожим (выбор без выбора)', E'{{имя}}, чтобы не терять время 🙂\n\nМогу взять вашу заявку в работу сегодня или завтра с утра — когда вам удобнее стартовать?\n\nЧем раньше начнём, тем раньше выйдете на сделку.', E'general', 26),
  (E'/молчание', E'17. Реанимация молчащего лида', E'{{имя}}, добрый день 👋 Это {{менеджер}}.\n\nМы с вами считали ипотеку, но потом связь оборвалась — не хочу быть навязчивым.\n\nСкажите прямо: вопрос ещё актуален или уже решили?\nЕсли решили — искренне рад 🙌 Если нет — я на связи, продолжим с того же места.', E'status', 27),
  (E'/рынок', E'18. Честная срочность (без выдуманных дедлайнов)', E'{{имя}}, момент, который стоит учесть 👇\n\nУсловия по госпрограммам и ставки пересматривают, а цены на квартиры не ждут. То, что проходит по расчёту сегодня, через пару месяцев может считаться иначе.\n\nЯ не тороплю — просто чем раньше зафиксируем, тем меньше сюрпризов.\n\nДавайте хотя бы посчитаем? Расчёт вас ни к чему не обязывает.', E'general', 28),
  (E'/первыйшаг', E'19. Снятие риска (бесплатный первый шаг)', E'{{имя}}, давайте без обязательств 🤝\n\nПервый шаг бесплатный: смотрю вашу ситуацию, считаю по программам и говорю честно — проходите или нет.\n\nНе проходите — так и скажу, брать деньги не за что.\nПроходите — покажу цифры, и уже вы решаете, работаем дальше или нет.\n\nИдёт?', E'general', 29),
  (E'/послеподписания', E'20. После подписания (онбординг)', E'{{имя}}, договор подписан — поздравляю, вы в работе! 🤝\n\nЧто дальше:\n1️⃣ Собираем документы (список пришлю следующим сообщением)\n2️⃣ Проверяю историю и готовлю заявку\n3️⃣ Подаём в банк\n4️⃣ Веду вас до выдачи денег\n\nЯ — {{менеджер}}, ваш специалист. Любой вопрос — пишите сюда, отвечаю лично.\n\nИдём за вашей квартирой 🔑', E'thanks', 30)
